WEB-CMDI-ID.remediation:
■ 안전한 코드 패턴

[Python — 취약]
import os
result = os.system("ping -c 1 " + user_input)

[Python — 안전 ✅]
import subprocess
result = subprocess.run(
    ["ping", "-c", "1", user_input],  # 리스트 형태
    capture_output=True,
    timeout=10
)
# 셸 인터프리터 거치지 않아 명령어 삽입 불가

[Java — 취약]
Runtime.getRuntime().exec("ping " + userInput);

[Java — 안전 ✅]
ProcessBuilder pb = new ProcessBuilder("ping", "-c", "1", userInput);
pb.redirectErrorStream(true);
Process p = pb.start();

[PHP — 취약]
exec("convert " . $_GET['file'] . " output.jpg");

[PHP — 안전 ✅]
$filename = basename($_GET['file']);  // 경로 제거
$whitelist = ['jpg','png','gif'];
if(in_array(pathinfo($filename, PATHINFO_EXTENSION), $whitelist)){
    exec("convert " . escapeshellarg($filename) . " output.jpg");
}

WEB-TRAV-LNX.remediation:
■ 안전한 파일 접근 코드

[Java — 취약]
String path = "/upload/" + request.getParameter("file");
File f = new File(path);
FileInputStream fis = new FileInputStream(f);

[Java — 안전 ✅]
String filename = request.getParameter("file");
Path basePath = Paths.get("/upload").toAbsolutePath().normalize();
Path resolvedPath = basePath.resolve(filename).normalize();
// 허용 경로 외부인지 검증
if (!resolvedPath.startsWith(basePath)) {
    throw new SecurityException("경로 탐색 시도 차단");
}

[Python — 안전 ✅]
import os
base_dir = '/var/www/uploads'
filename = request.args.get('file', '')
safe_path = os.path.realpath(os.path.join(base_dir, filename))
if not safe_path.startswith(base_dir):
    return abort(403)

[nginx 설정]
# 업로드 디렉토리 외부 접근 차단
location /uploads {
    alias /var/www/uploads/;
    if ($uri ~* "\.\.") { return 403; }
}

WEB-TRAV-WIN.remediation:
[IIS 설정]
  <system.web>
    <customErrors mode="On" defaultRedirect="~/Error"/>
  </system.web>

  [C# — 안전한 파일 접근]
  string basePath = Server.MapPath("~/uploads");
  string requestedFile = Path.GetFileName(Request["file"]);
  string fullPath = Path.Combine(basePath, requestedFile);
  // GetFileName으로 경로 구분자 제거
  if (!fullPath.StartsWith(basePath))
      throw new SecurityException();

